custom_css:
/* ==========================================================
   名称：神秘紫色魔法主题
   样式作者：@Junezz 改
   版本：v1.1
   基于：复古MacOS UI

   神秘紫色魔法风格主题，带有金色装饰和星辰元素
   ========================================================== */

@import url("https://fontsapi.zeoseven.com/570/main/result.css");

body {
    font-family: "Fusion Pixel 12px Monospaced zh_hans";
    font-weight: normal;
    background: linear-gradient(180deg, #190c30 0%, #150a25 50%, #0f061a 100%);
    background-attachment: fixed;
}

body::before {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
    background-image: 
        radial-gradient(2px 2px at 20px 30px, rgba(255, 215, 100, 0.3), transparent),
        radial-gradient(2px 2px at 40px 70px, rgba(180, 140, 220, 0.2), transparent),
        radial-gradient(1px 1px at 90px 40px, rgba(255, 215, 100, 0.4), transparent),
        radial-gradient(2px 2px at 130px 80px, rgba(230, 180, 255, 0.3), transparent),
        radial-gradient(1px 1px at 160px 120px, rgba(255, 215, 100, 0.2), transparent),
        radial-gradient(2px 2px at 200px 50px, rgba(180, 140, 220, 0.3), transparent),
        radial-gradient(1px 1px at 250px 150px, rgba(255, 215, 100, 0.4), transparent),
        radial-gradient(2px 2px at 300px 90px, rgba(230, 180, 255, 0.2), transparent),
        radial-gradient(1px 1px at 350px 200px, rgba(255, 215, 100, 0.3), transparent),
        radial-gradient(2px 2px at 400px 160px, rgba(180, 140, 220, 0.4), transparent);
    animation: twinkle 5s ease-in-out infinite;
    z-index: -1;
}

@keyframes twinkle {
    0%, 100% { opacity: 0.5; }
    50% { opacity: 1; }
}

code, textarea, #send_textarea, input, select, button, .text_pole, .font-family-reset {
  font-family: inherit;
}

:root {
    --mainFontSize: calc(var(--fontScale)* 16px);
    --avatar-base-width: 48px;
    --avatar-base-height: 48px;
    --topbarIconSize: calc(var(--mainFontSize)* 1.3);
    --genericRadius: 12px;
    --warning: #ff6b6b;
    --crimson70a: rgba(230, 180, 255, 0.4);
    --crimson-hover: color-mix(in srgb, rgba(255, 215, 100, 0.2), transparent 80%) !important;
    --standardIconSize: calc(var(--mainFontSize)* 1);
    --bottomFormIconSize: calc(var(--mainFontSize)* 1.5);
    --bottomFormBlockPadding: calc(var(--mainFontSize) / 1.5);
    --scrollBarWidth: 6px;
    --pagePadding: calc(var(--scrollBarWidth) + 9px);
    --genericLineHeight: calc(var(--mainFontSize)* 1.8);

    --utilityColor: rgba(230, 180, 255, 0.7);
    --navBackgroundColor: rgba(25, 12, 50, 0.98);
    --buttonFill: rgba(50, 25, 85, 0.85);
    --menuBackgroundColor: rgba(35, 18, 70, 0.98);
    --accentColor: rgba(255, 215, 100, 1);
    --accentColorOverlay: rgba(180, 140, 220, 0.15);
    --scrollBarColor: rgba(180, 140, 220, 0.8);
    --boxShadowSubtle: 0 0 20px rgba(180, 140, 220, 0.3);
    --boxShadowSubtleAlt: 0 0 25px rgba(255, 215, 100, 0.3);
    --goldGradient: linear-gradient(135deg, #ffd700 0%, #ffb700 50%, #ffd700 100%);
    --purpleGradient: linear-gradient(135deg, #6b21a8 0%, #4c1d95 100%);
  }

#chat {
    padding: 0 !important;
    overflow-y: scroll;
    border: none !important;
    border-top: none;
    border-bottom: none;
}

#form_sheld {
    margin-top: 0px !important;
}

#top-bar {
    height: var(--topBarBlockSize);
    background: linear-gradient(180deg, rgba(35, 18, 70, 0.98), rgba(25, 12, 50, 0.95)) !important;
    border-bottom: 1px solid rgba(255, 215, 100, 0.3);
    box-shadow: 0 2px 20px rgba(180, 140, 220, 0.2);
}

#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4,
.standoutHeader,
.userSettingsInnerExpandable {
    border: transparent !important;
}

.drawer-content, #right-nav-panel, #left-nav-panel {
    background: linear-gradient(180deg, rgba(35, 18, 70, 0.98), rgba(25, 12, 50, 0.95)) !important;
    border-radius: var(--genericRadius);
    padding: 12px;
    border: 1px solid rgba(255, 215, 100, 0.3);
    box-shadow: 0 0 20px rgba(180, 140, 220, 0.2);
}

#right-nav-panel {
    border-left: none;
}

#left-nav-panel {
    border-right: none;
}

.fa, .fa-brands, .fa-classic, .fa-regular, .fa-sharp, .fa-solid, .fab, .far, .fas {
    font-size: var(--standardIconSize);
    color: rgba(255, 215, 100, 0.9);
}

#character_sort_order,
#form_character_search_form .menu_button, 
#GroupFavDelOkBack .menu_button,
.regex-script-label,
.menu_button {
    border-radius: var(--genericRadius) !important;
    background: linear-gradient(135deg, rgba(50, 25, 85, 0.9), rgba(40, 20, 70, 0.85)) !important;
    border: 1px solid rgba(255, 215, 100, 0.3) !important;
    color: rgba(230, 180, 255, 0.9) !important;
}

.menu_button:hover {
    background: linear-gradient(135deg, rgba(70, 35, 110, 0.95), rgba(50, 25, 85, 0.9)) !important;
    border-color: rgba(255, 215, 100, 0.6) !important;
    box-shadow: 0 0 15px rgba(255, 215, 100, 0.4) !important;
    transform: translateY(-1px);
}

.drawer-icon::before {
    content: "";
    width: var(--topbarIconSize);
    height: var(--topbarIconSize);
    background-size: cover;
    display: inline-block;
    background-position: center;
    background-repeat: no-repeat;
    background: var(--goldGradient);
    mask-repeat: no-repeat;
    mask-position: center;
    mask-size: cover;
    -webkit-mask-repeat: no-repeat;
    -webkit-mask-position: center;
    -webkit-mask-size: cover;
}

.drawer-icon.closedIcon {
    font-size: var(--topbarIconSize);
    opacity: 0.8;
}

.drawer-icon.openIcon {
    font-size: var(--topbarIconSize);
    transform: scale(1.2);
    filter: drop-shadow(0 0 8px rgba(255, 215, 100, 0.6));
}

.drawer-icon.closedIcon:hover {
    transform: scale(1.2);
    filter: drop-shadow(0 0 8px rgba(255, 215, 100, 0.5));
}

#leftNavDrawerIcon::before {
    mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/preset.svg");
    -webkit-mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/preset.svg");
}
#sys-settings-button .drawer-icon::before {
    mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/connection.svg");
    -webkit-mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/connection.svg");
}
#advanced-formatting-button .drawer-icon::before {
    mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/format.svg");
    -webkit-mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/format.svg");
}
#WI-SP-button .drawer-icon::before {
    mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/Worldinfo.svg");
    -webkit-mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/Worldinfo.svg");
}
#user-settings-button .drawer-icon::before {
    mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/Settings.svg");
    -webkit-mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/Settings.svg");
}
#logo_block .drawer-icon::before {
    mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/background.svg");
    -webkit-mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/background.svg");
}
#extensions-settings-button .drawer-icon::before {
    mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/Extensions.svg");
    -webkit-mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/Extensions.svg");
}
#table_database_settings_drawer .drawer-icon::before {
    mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/table.svg");
    -webkit-mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/table.svg");
}
#persona-management-button .drawer-icon::before {
    mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/persona.svg");
    -webkit-mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/persona.svg");
}
#rightNavDrawerIcon::before {
    mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/character.svg");
    -webkit-mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/character.svg");
}

#rightSendForm>div, #leftSendForm>div {
    font-size: var(--bottomFormIconSize) !important;
    border-radius: 100px;
    color: rgba(255, 215, 100, 0.9);
    position: relative;
}

#options_button::before,
#extensionsMenuButton::before,
#send_but::before,
.fa-solid.fa-circle-stop::before {
    content: "";
    position: relative;
    width: var(--bottomFormIconSize);
    height: var(--bottomFormIconSize);
    background-size: cover;
    display: inline-block;
    background-position: center;
    background-repeat: no-repeat;
    background: var(--goldGradient);
    mask-repeat: no-repeat;
    mask-position: center;
    mask-size: cover;
    -webkit-mask-repeat: no-repeat;
    -webkit-mask-position: center;
    -webkit-mask-size: cover;
}

#rightSendForm>div:not(.mes_stop):hover, #leftSendForm>div:hover, .fa-solid.fa-circle-stop:hover {
    transform: scale(1.1);
    filter: drop-shadow(0 0 10px rgba(255, 215, 100, 0.5));
}

#options_button::before {
    mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/option.svg");
    -webkit-mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/option.svg");
}
#extensionsMenuButton::before {
    mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/exten.svg");
    -webkit-mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/exten.svg");
}
#send_but::before {
    mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/send.svg");
    -webkit-mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/send.svg");
}
.fa-solid.fa-circle-stop::before {
    mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/stop.svg");
    -webkit-mask-image: url("https://cdn.jsdelivr.net/gh/Junejulyz/MacOSStyleAsset@main/stop.svg");
}

#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4, .standoutHeader{
    background-image: none !important;
    padding: 2px 0 !important;
}

.standoutHeader:not(h4),
#rm_PinAndTabs,
#title_api,
#rm_api_block .flex-container.alignItemsBaseline,
#AdvancedFormatting .flex-container.alignItemsBaseline:not(h3),
#WorldInfo .alignitemscenter:not(#world_popup *),
#user-settings-block div[name="userSettingsRowOne"],
#rm_extensions_block .alignitemscenter.flex-container.wide100p:not(.justifyCenter),
#top-settings-holder .drawer:not(:first-child):not(:last-child) .drawer-content .alignItemsBaseline.wide100p {
    position: relative;
    padding-left: 12px;
    margin-top: calc(var(--mainFontSize) * 0.2) !important;
    margin-bottom: calc(var(--mainFontSize) * 0.2) !important;
}

#rm_PinAndTabs::before,
#title_api::before,
#rm_api_block .flex-container.alignItemsBaseline::before,
#AdvancedFormatting .flex-container.alignItemsBaseline:not(h3)::before,
#WorldInfo .alignitemscenter:not(#world_popup *)::before,
#user-settings-block div[name="userSettingsRowOne"]::before,
#rm_extensions_block .alignitemscenter.flex-container.wide100p:not(.justifyCenter)::before,
#top-settings-holder .drawer:not(:first-child):not(:last-child) .drawer-content .alignItemsBaseline.wide100p::before {
    content: '';
    position: absolute;
    left: 0;
    top: 6px;
    bottom: 6px;
    width: 3px;
    background: var(--goldGradient);
    border-radius: 2px;
}

.standoutHeader strong,
#right-nav-panel h2,
.drawer-content > h3,
.drawer-content .flex-container h3:first-of-type:not(#Backgrounds .textAlignCenter),
.drawer-content .flex-container .flex-container h3:first-of-type,
.popup h3:not(dialog *) {
    line-height: var(--genericLineHeight);
    color: rgba(255, 215, 100, 0.95);
}

.flex-container {
    gap: 8px;
}

.redOverlayGlow {
    color: rgba(255, 100, 150, 0.8);
}

body .mes[is_user="false"]{
    margin-top: 8px;
    margin-bottom: 16px;
}

.ui-widget.ui-widget-content,
#bulk_tag_popup,
#dialogue_popup,
.popup,
#options,
#extensionsMenu,
.popup .popper-modal,
.select2-dropdown,
#select_chat_popup,
#floatingPrompt,
#cfgConfig,
#logprobsViewer,
#movingDivs > div {
    border-radius: var(--genericRadius);
    background: linear-gradient(180deg, rgba(35, 18, 70, 0.98), rgba(25, 12, 50, 0.95));
    border: 1px solid rgba(255, 215, 100, 0.3);
    box-shadow: 0 0 25px rgba(180, 140, 220, 0.3);
}

.extensions_toolbar {
    background: linear-gradient(180deg, rgba(35, 18, 70, 0.98), rgba(25, 12, 50, 0.95));
}

#ccs-preview-modal > div,
.bg_example, #toast-container > div,
.bg_example:hover, #toast-container > div:hover {
    border-radius: var(--genericRadius) !important;
    border: 1px solid rgba(255, 215, 100, 0.3) !important;
    box-shadow: 0 0 20px rgba(180, 140, 220, 0.3) !important;
}

.list-group, .extensions_info .extension_block, #completion_prompt_manager_popup {
    border-radius: var(--genericRadius);
    border: 1px solid rgba(255, 215, 100, 0.3);
}

.bg_example.no-border.no-shadow.add_bg_but.interactable {
    background: var(--goldGradient);
}

body .ui-widget-content li:hover {
    background-color: rgba(255, 215, 100, 0.2);
}

.tag {
    background: linear-gradient(135deg, rgba(50, 25, 85, 0.9), rgba(40, 20, 70, 0.85));
    border: 1px solid rgba(255, 215, 100, 0.3);
    border-radius: 4px;
}

.red_button:hover {
    background-color: var(--crimson-hover) !important;
}

.select2-container .select2-selection--multiple, .select2-container .select2-selection--single,
.select2-results__option::before,
.select2-results__option--selected.select2-results__option::before {
    background: linear-gradient(135deg, rgba(50, 25, 85, 0.9), rgba(40, 20, 70, 0.85));
}

.select2-container .select2-selection--multiple, .select2-container .select2-selection--single,
.select2-container .select2-selection--multiple .select2-selection__choice, .select2-container .select2-selection--single .select2-selection__choice,
.select2-container--default .select2-selection--multiple .select2-selection__choice,
.standoutHeader~.inline-drawer-content {
    box-shadow: 0 0 15px rgba(180, 140, 220, 0.2);
    border-radius: var(--genericRadius);
}

.standoutHeader~.inline-drawer-content {
    background: linear-gradient(180deg, rgba(35, 18, 70, 0.98), rgba(25, 12, 50, 0.95));
}

.wi-card-entry {
    margin-top: 12px;
    padding: 12px;
    background: rgba(180, 140, 220, 0.1);
    border: 1px solid rgba(255, 215, 100, 0.3);
    border-radius: var(--genericRadius);
}

body.bubblechat .mes {
    border-radius: var(--genericRadius);
    padding: 0px 0px 16px 0px;
    display: flex;
    flex-direction: column;
    border: none !important;
    box-shadow: none !important;
}

.mesAvatarWrapper {
    display: flex;
    background: rgba(180, 140, 220, 0.1);
    flex-direction: row;
    align-items: center;
    gap: 10px;
    padding: 16px 16px 0px 16px;
    border-radius: var(--genericRadius);
    overflow: hidden;
    width: 100%;
    padding-bottom: 3px;
    border: 1px solid rgba(255, 215, 100, 0.2);
}

body.bubblechat .mes[is_user="true"] .mesAvatarWrapper {
    flex-direction: row-reverse;
}

.mes .avatar img{
    padding: 0px;
}

body.square-avatars .avatar, body.square-avatars .avatar img{
    border-radius: var(--genericRadius) !important;
}

.avatar img {
    box-shadow: 0 0 15px rgba(180, 140, 220, 0.4) !important;
}

.mes_block .ch_name {
    background: rgba(180, 140, 220, 0.1);
    border-radius: var(--genericRadius);
    padding: 14px 16px;
    margin-bottom: 10px;
    border: 1px solid rgba(255, 215, 100, 0.2);
    box-shadow: 0 0 15px rgba(180, 140, 220, 0.15);
}

.mes_text {
    padding: 0px 4px !important;
    line-height: var(--genericLineHeight);
}

.mes_text p {
    margin-bottom: 14px;
    position: relative;
}

.mes_text p::after {
    content: '';
    position: absolute;
    bottom: -4px;
    left: 0;
    right: 0;
    height: 8px;
    background: repeating-linear-gradient(90deg, 
        rgba(180, 140, 220, 0.3) 0px,
        rgba(180, 140, 220, 0.3) 2px,
        transparent 2px,
        transparent 4px,
        rgba(180, 140, 220, 0.2) 4px,
        rgba(180, 140, 220, 0.2) 6px,
        transparent 6px,
        transparent 8px);
}

.mes_edit_buttons {
    filter: drop-shadow(0px 0px 4px rgba(255, 215, 100, 0.5));
}

.mes_text blockquote, .mes_reasoning blockquote {
    background: rgba(25, 12, 50, 0.9);
    border-left: 3px solid rgba(255, 215, 100, 0.8);
    padding: 12px 16px;
    margin-bottom: 12px;
    border-radius: 0 var(--genericRadius) var(--genericRadius) 0;
    border: 1px solid rgba(255, 215, 100, 0.2);
    position: relative;
}

.mes_text blockquote::before {
    content: '✦';
    position: absolute;
    left: -8px;
    top: 8px;
    color: rgba(255, 215, 100, 0.6);
    font-size: 1.1em;
}

.extensions_info .extension_disabled {
    color: var(--SmartThemeEmColor);
}

.integrated-button-row {
    background: linear-gradient(180deg, rgba(35, 18, 70, 0.98), rgba(25, 12, 50, 0.95)) !important;
}

#send_form {
    background: linear-gradient(180deg, rgba(35, 18, 70, 0.98), rgba(25, 12, 50, 0.95)) !important;
    padding: 8px 12px;
    border: 1px solid rgba(255, 215, 100, 0.3);
    border-radius: var(--genericRadius);
    box-shadow: 0 0 20px rgba(180, 140, 220, 0.2);
}

body.no-blur #send_form {
    background: linear-gradient(180deg, rgba(35, 18, 70, 0.98), rgba(25, 12, 50, 0.95)) !important;
}

input[type='checkbox'] {
    background: linear-gradient(135deg, rgba(50, 25, 85, 0.9), rgba(40, 20, 70, 0.85));
    border: 1px solid rgba(255, 215, 100, 0.4);
    border-radius: var(--genericRadius);
}

input[type="checkbox"]::before {
    box-shadow: inset 1em 1em rgba(255, 215, 100, 0.9);
}

#completion_prompt_manager_list {
    background: linear-gradient(180deg, rgba(35, 18, 70, 0.98), rgba(25, 12, 50, 0.95)) !important;
    padding: 0px 8px;
    border: none !important;
    box-shadow: none !important;
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt {
    background: linear-gradient(135deg, rgba(50, 25, 85, 0.9), rgba(40, 20, 70, 0.85));
    border: 1px solid rgba(255, 215, 100, 0.3);
    border-radius: var(--genericRadius);
    padding: 10px;
    margin-bottom: 8px;
}

.text_muted {
    color: rgba(230, 180, 255, 0.6);
}

.mes_text q {
    color: var(--SmartThemeQuoteColor);
    background: rgba(180, 140, 220, 0.15);
    margin: 0px 6px 0px 3px;
    padding: 6px 8px;
    font-size: calc(var(--mainFontSize)* 0.98);
    border-radius: 4px;
    border: 1px solid rgba(255, 215, 100, 0.2);
}

code {
    background: rgba(180, 140, 220, 0.15);
    color: rgba(230, 180, 255, 0.9);
    border: none;
    border-bottom: 2px dashed rgba(255, 215, 100, 0.6);
    border-radius: 4px;
    font-size: calc(var(--mainFontSize)* 0.98);
    padding: 4px 6px;
}

hr {
    background-image: none;
    background: linear-gradient(90deg, transparent, rgba(255, 215, 100, 0.5), transparent);
    margin: 16px 0px;
    height: 1px;
    border: none;
}

select, .range-block-counter input, .text_pole, textarea, .neo-range-input {
    filter: none !important;
    background: linear-gradient(135deg, rgba(50, 25, 85, 0.9), rgba(40, 20, 70, 0.85)) !important;
    border: 1px solid rgba(255, 215, 100, 0.3) !important;
    margin: 4px 0px !important;
    border-radius: var(--genericRadius);
    color: rgba(230, 180, 255, 0.9) !important;
}

#send_textarea {
    background: transparent !important;
    font-size: calc(var(--mainFontSize) - 1px);
    color: rgba(230, 180, 255, 0.9) !important;
    border: 1px solid rgba(255, 215, 100, 0.2) !important;
    border-radius: var(--genericRadius);
    padding: 12px;
    transition: all 0.3s ease;
}

#send_textarea:focus {
    border-color: rgba(255, 215, 100, 0.5) !important;
    box-shadow: 0 0 20px rgba(255, 215, 100, 0.3) !important;
}

#send_textarea::placeholder {
    color: rgba(180, 140, 220, 0.5);
}

input.neo-range-slider[type="range"]::-webkit-slider-thumb {
    border-radius: var(--genericRadius) !important;
    width: 14px;
    height: 14px;
    border: none;
    box-shadow: 0 0 10px rgba(255, 215, 100, 0.6);
    background: var(--goldGradient) !important;
}

input.neo-range-slider[type="range"] {
    border-radius: var(--genericRadius) !important;
    box-shadow: none !important;
    background: rgba(180, 140, 220, 0.3) !important;
    opacity: 0.8;
}

.range-block-range input[type="range"]::-webkit-slider-thumb {
    border-radius: var(--genericRadius) !important;
    width: 14px;
    height: 14px;
    border: none;
    box-shadow: 0 0 10px rgba(255, 215, 100, 0.6);
    background: var(--goldGradient) !important;
}

.range-block-range input[type="range"] {
    border-radius: var(--genericRadius) !important;
    box-shadow: none;
    background: rgba(180, 140, 220, 0.3) !important;
}

#rm_print_characters_pagination {
    background: linear-gradient(180deg, rgba(35, 18, 70, 0.98), rgba(25, 12, 50, 0.95));
    border-radius: var(--genericRadius);
    padding: 10px;
    margin: 8px;
    border: 1px solid rgba(255, 215, 100, 0.3);
}

.avatar-container.selected {
    border: 2px solid rgba(255, 215, 100, 0.6);
    border-radius: var(--genericRadius);
    box-shadow: 0 0 15px rgba(255, 215, 100, 0.4);
}

.avatar-container:hover {
    background: rgba(180, 140, 220, 0.15);
}

.add_avatar:hover {
    filter: drop-shadow(0px 0px 6px rgba(255, 215, 100, 0.8));
}

.character_select.is_fav .ch_name, .group_select.is_fav .ch_name, .group_member.is_fav .ch_name {
    color: rgba(255, 215, 100, 0.95);
}

.character_select.is_fav .avatar {
    outline: 2px solid rgba(255, 215, 100, 0.8);
    box-shadow: 0 0 15px rgba(255, 215, 100, 0.4);
}

.mes_reasoning_header {
    border: 1px solid rgba(255, 215, 100, 0.6);
    border-radius: var(--genericRadius);
    background: rgba(180, 140, 220, 0.1);
    justify-content: center;
    letter-spacing: 0.5px;
    margin: 0px;
    transition: all 0.25s ease;
    cursor: pointer;
    box-shadow: 0 0 15px rgba(180, 140, 220, 0.2);
}

.mes_reasoning_header:hover {
    background: rgba(255, 215, 100, 0.1);
    box-shadow: 0 0 20px rgba(255, 215, 100, 0.3);
}

.mes_reasoning {
    border-left: 2px solid rgba(255, 215, 100, 0.6);
    color: var(--SmartThemeBodyColor);
    background: rgba(180, 140, 220, 0.05);
}

::-webkit-scrollbar {
    width: var(--scrollBarWidth);
    height: var(--scrollBarWidth);
}

::-webkit-scrollbar-track {
    background: rgba(25, 12, 50, 0.5);
    border-radius: var(--scrollBarWidth);
}

::-webkit-scrollbar-thumb:vertical,
::-webkit-scrollbar-thumb:horizontal {
    border-radius: var(--scrollBarWidth);
    background: linear-gradient(180deg, rgba(180, 140, 220, 0.8), rgba(140, 100, 180, 0.6));
    border: 1px solid rgba(255, 215, 100, 0.3);
    box-shadow: 0 0 10px rgba(180, 140, 220, 0.5);
}

.mes_text table {
    width: 100%;
    border-collapse: collapse;
    margin: 12px 0;
    color: rgba(230, 180, 255, 0.9);
    background: rgba(180, 140, 220, 0.1);
    border-radius: var(--genericRadius);
    overflow: hidden;
    border: 1px solid rgba(255, 215, 100, 0.3);
    box-shadow: 0 0 20px rgba(100, 50, 150, 0.2);
}

.mes_text th,
.mes_text td {
    border: none;
    border-right: 1px solid rgba(255, 215, 100, 0.2);
    padding: 12px 16px;
    text-align: left;
    border-bottom: 1px solid rgba(255, 215, 100, 0.2);
}

.mes_text th {
    font-weight: 700;
    background: rgba(255, 215, 100, 0.1);
}

.mes_text tr:nth-child(even) {
    background: rgba(255, 255, 255, 0.02);
}

.mes_text pre {
    background: rgba(25, 12, 50, 0.95);
    padding: 14px 16px;
    border-radius: var(--genericRadius);
    font-family: inherit;
    font-size: calc(var(--mainFontSize)* 0.95);
    letter-spacing: 0.3px;
    overflow-x: auto;
    white-space: pre-wrap;
    word-break: break-word;
    border-left: 3px solid rgba(255, 215, 100, 0.8);
    border: 1px solid rgba(255, 215, 100, 0.2);
    box-shadow: 0 0 20px rgba(100, 50, 150, 0.3);
}

.mes_text pre code {
    font-family: inherit;
    color: inherit;
    background: none;
    border: none;
}

#InstructSettingsColumn .text_pole,
#InstructSettingsColumn select,
#InstructSettingsColumn .menu_button,
#InstructSettingsColumn input[type='checkbox'] {
    background: rgba(40, 20, 70, 0.8) !important;
}

#HotSwapWrapper > div {
    overflow: auto hidden;
    flex-wrap: nowrap;
    justify-content: flex-start;
    gap: 10px;
    min-height: calc(var(--avatar-base-height)* 1.5);
}

#HotSwapWrapper > div::-webkit-scrollbar-thumb {
    background: linear-gradient(180deg, rgba(180, 140, 220, 0.8), rgba(140, 100, 180, 0.6));
}

@media (max-width: 600px) {
    #rm_extensions_block {
        padding-right: 24px;
    }
    #bg_menu_content {
        width: 100%;
    }
    #character-script-list, #global-script-list, #saved_scoped_scripts, #saved_regex_scripts {
        flex-wrap: wrap !important;
        max-width: 75vw;
    }
    .regex-script-label, #global-script-list .script-item, #character-script-list .script-item {
        max-width: 75vw;
        flex-wrap: wrap;
        border-radius: var(--genericRadius) !important;
        background: linear-gradient(135deg, rgba(50, 25, 85, 0.9), rgba(40, 20, 70, 0.85)) !important;
        gap: 4px !important;
        padding-top: 8px !important;
        padding-bottom: 4px !important;
        border: 1px solid rgba(255, 215, 100, 0.3) !important;
        box-shadow: 0 0 15px rgba(180, 140, 220, 0.2) !important;
    }
    .regex-script-label:has(.disable_regex:checked),
    #global-script-list .script-item:not(:has(.script-toggle.enabled)),
    #character-script-list .script-item:not(:has(.script-toggle.enabled)) {
        background: rgba(180, 140, 220, 0.1) !important;
        border: none !important;
        border-left: 2px solid rgba(255, 215, 100, 0.6) !important;
        box-shadow: none !important;
    }
}

@supports (-webkit-touch-callout: none) {
    #chat {
        padding-right: var(--pagePadding);
    }
    .drawer-content:not(#left-nav-panel):not(#right-nav-panel) {
        max-width: 100dvw;
    }
    #world_popup {
        width: 100%;
    }
}

@supports (-webkit-touch-callout: none) {
    @media screen and (min-width: 768px) {
        #sheld {
            width: var(--sheldWidth);
            margin-left: auto;
            margin-right: auto;
        }
        #top-bar, #top-settings-holder .drawer .drawer-content {
            width: var(--sheldWidth);
        }
        #left-nav-panel,
        #right-nav-panel,
        #character_popup,
        #world_popup,
        .drawer-content {
            top: var(--topBarBlockSize);
        }
        #character_popup,
        #world_popup,
        .drawer-content {
            margin-top: 0px;
            top: var(--topBarBlockSize);
        }
    }
}

#settings-panel input, #settings-panel select, #settings-panel textarea,
#settings-panel2 input, #settings-panel2 select {
